const item = $json;

function get(obj, path, def = undefined) {
  return path.split('.').reduce((a, b) => (a && a[b] !== undefined) ? a[b] : def, obj);
}

const mcat_id = item.mcat_id || get(item, 'mcatId') || null;

let url = get(item, 'finalized_specs.file_info.url');

if (!url) {
  const fileInfo = get(item, 'finalized_specs.file_info');
  if (Array.isArray(fileInfo) && fileInfo.length > 0) {
    url = fileInfo[0].url || fileInfo[0].download_url || null;
  }
}

if (!url) {
  const jsonStr = JSON.stringify(item);
  const m = jsonStr.match(/https:\/\/storage\.googleapis\.com\/[^\s"']+/);
  if (m) url = m[0];
}

return [{ json: { mcat_id, finalized_spec_url: url || null } }];

// Extract and store seller specs for downstream use
const sellerData = $json;

const primary = sellerData.finalized_specs?.finalized_primary_specs?.specs || [];
const secondary = sellerData.finalized_specs?.finalized_secondary_specs?.specs || [];
const tertiary = sellerData.finalized_specs?.finalized_tertiary_specs?.specs || [];

const current_specs = [];

primary.forEach(s => {
  current_specs.push({
    spec_name: s.spec_name,
    options: s.options || [],
    input_type: s.input_type || "radio_button",
    tier: "Primary"
  });
});

secondary.forEach(s => {
  current_specs.push({
    spec_name: s.spec_name,
    options: s.options || [],
    input_type: s.input_type || "radio_button",
    tier: "Secondary"
  });
});

tertiary.forEach(s => {
  current_specs.push({
    spec_name: s.spec_name,
    options: s.options || [],
    input_type: s.input_type || "radio_button",
    tier: "Tertiary"
  });
});

return [{
  json: {
    mcat_id: sellerData.mcat_id,
    mcat_name: sellerData.category_name,
    current_specs,
    raw_seller_specs: sellerData
  }
}];

const items = $input.all();

const output = items.map(item => {
  const data = item.json;
  const mcatId = data["Mcat Id"];
  const mcatName = data["Mcat Name"];

  let missingSpecs = [];
  try {
    missingSpecs = JSON.parse(data["Missing Spec"] || "[]");
  } catch (e) {
    missingSpecs = [];
  }

  const custom_specs = missingSpecs.map(spec => ({
    spec_name: spec.spec_name,
    sample_values: spec.options || []
  }));

  return {
    json: {
      mcat_id: mcatId,
      mcat_name: mcatName,
      custom_specs: custom_specs,
      source: "custom_specs"
    }
  };
});

return output.length > 0 ? output : [{ json: { custom_specs: [], source: "custom_specs" } }];

const rows = $input.all();

const specMap = {};
let mcat_name = null;

for (const item of rows) {
  const spec = item.json.spec_name;
  const values = item.json.example_values;

  if (!mcat_name && item.json.category) {
    mcat_name = item.json.category;
  }

  if (!spec) continue;

  if (!specMap[spec]) {
    specMap[spec] = {
      spec_name: spec,
      sample_values: []
    };
  }

  if (values) {
    const splitValues = String(values)
      .split(',')
      .map(v => v.trim())
      .filter(v => v.length > 0);

    for (const val of splitValues) {
      if (!specMap[spec].sample_values.includes(val)) {
        specMap[spec].sample_values.push(val);
      }
    }
  }
}

const result = Object.values(specMap).map(spec => ({
  spec_name: spec.spec_name,
  sample_values: spec.sample_values.slice(0, 5)
}));

return [{
  json: {
    mcat_name,
    buyer_specs: result,
    source: "buyer_seller_call"
  }
}];

const rows = $input.all();

const specMap = {};
let mcat_name = null;

for (const item of rows) {
  // Try multiple possible column names
  const spec = item.json.spec_name || item.json.search_spec || item.json.attribute;
  const values = item.json.example_values || item.json.search_values || item.json.values || item.json.search_terms;

  if (!mcat_name && (item.json.category || item.json.mcat_name)) {
    mcat_name = item.json.category || item.json.mcat_name;
  }

  if (!spec) continue;

  if (!specMap[spec]) {
    specMap[spec] = {
      spec_name: spec,
      sample_values: []
    };
  }

  if (values) {
    const splitValues = String(values)
      .split(',')
      .map(v => v.trim())
      .filter(v => v.length > 0);

    for (const val of splitValues) {
      if (!specMap[spec].sample_values.includes(val)) {
        specMap[spec].sample_values.push(val);
      }
    }
  }
}

const result = Object.values(specMap).map(spec => ({
  spec_name: spec.spec_name,
  sample_values: spec.sample_values.slice(0, 5)
}));

return [{
  json: {
    mcat_name,
    buyer_search_specs: result,
    source: "buyer_search_data"
  }
}];

// Combine all sources into unified candidate specs
const items = $input.all();

// Get current specs from the first pipeline
const currentSpecsNode = $items("Current Specs")[0].json;
const mcat_id = currentSpecsNode.mcat_id;
const mcat_name = currentSpecsNode.mcat_name;
const current_specs = currentSpecsNode.current_specs || [];

// Collect all candidate specs from merged sources
let custom_specs = [];
let buyer_specs = [];
let buyer_search_specs = [];

for (const item of items) {
  const data = item.json;

  if (data.custom_specs) {
    custom_specs = data.custom_specs;
  }
  if (data.buyer_specs) {
    buyer_specs = data.buyer_specs;
  }
  if (data.buyer_search_specs) {
    buyer_search_specs = data.buyer_search_specs;
  }
}

// Build unified candidate specs array with source tracking
const candidate_specs = [];

// Add custom specs
for (const spec of custom_specs) {
  candidate_specs.push({
    spec_name: spec.spec_name,
    sample_values: spec.sample_values || [],
    source: "custom_specs"
  });
}

// Add buyer seller call specs
for (const spec of buyer_specs) {
  candidate_specs.push({
    spec_name: spec.spec_name,
    sample_values: spec.sample_values || [],
    source: "buyer_seller_call"
  });
}

// Add buyer search specs
for (const spec of buyer_search_specs) {
  candidate_specs.push({
    spec_name: spec.spec_name,
    sample_values: spec.sample_values || [],
    source: "buyer_search_data"
  });
}

// Store for downstream nodes
return [{
  json: {
    mcat_id,
    mcat_name,
    current_specs,
    candidate_specs,
    custom_specs,
    buyer_specs,
    buyer_search_specs,
    summary: {
      current_specs_count: current_specs.length,
      custom_specs_count: custom_specs.length,
      buyer_specs_count: buyer_specs.length,
      buyer_search_specs_count: buyer_search_specs.length,
      total_candidates: candidate_specs.length
    }
  }
}];

const raw = $json.output || "";

// Remove markdown wrappers
let cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

// Extract JSON object
const start = cleaned.indexOf("{");
const end = cleaned.lastIndexOf("}");

if (start !== -1 && end !== -1) {
  cleaned = cleaned.slice(start, end + 1);
}

// Fix common LLM JSON mistakes
cleaned = cleaned
  .replace(/,\s*,/g, ",")
  .replace(/,\s*}/g, "}")
  .replace(/,\s*]/g, "]");

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error("AI Agent 1 returned invalid JSON: " + cleaned.substring(0, 500));
}

return [{ json: parsed }];

let raw = $json.output || "";

raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

const start = raw.indexOf("{");
const end = raw.lastIndexOf("}");

if (start !== -1 && end !== -1) {
  raw = raw.substring(start, end + 1);
}

raw = raw
  .replace(/,\s*]/g, "]")
  .replace(/,\s*}/g, "}");

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  throw new Error("Failed to parse AI Agent 3 JSON: " + raw.substring(0, 500));
}

return [{ json: parsed }];

const sellerNode = $items("Current Specs")[0].json;
const optionNode = $items("Parse Agent 3 Output")[0].json;

const mcat_id = sellerNode.mcat_id;
const mcat_name = sellerNode.mcat_name;

const sellerSpecs = sellerNode.current_specs || [];
const candidates = optionNode.finalized_specs_with_options || [];

const finalSpecs = [];

// Seller specs
for (const spec of sellerSpecs) {
  finalSpecs.push({
    spec_name: spec.spec_name,
    tier: spec.tier,
    source: "seller",
    reason: "Existing seller specification.",
    options: spec.options || [],
    input_type: spec.input_type || "radio_button"
  });
}

// Candidate specs
for (const spec of candidates) {
  finalSpecs.push({
    spec_name: spec.spec_name,
    tier: "Tertiary",
    source: "candidate",
    reason: "Missing specification discovered from external signals.",
    options: spec.options || [],
    input_type: spec.input_type || "radio_button"
  });
}

return [{
  json: {
    mcat_id,
    mcat_name,
    finalized_specs: finalSpecs,
    not_added_specs: []
  }
}];

const data = $json;

const mcatId = data.mcat_id;
const mcatName = data.mcat_name;
const specs = data.finalized_specs || [];

const primary = [];
const secondary = [];
const tertiary = [];

specs.forEach(spec => {
  const specObj = {
    spec_name: spec.spec_name,
    options: spec.options || [],
    input_type: spec.input_type || "radio_button"
  };

  const tier = (spec.tier || "").toLowerCase();

  if (tier === "primary") primary.push(specObj);
  else if (tier === "secondary") secondary.push(specObj);
  else tertiary.push(specObj);
});

return [{
  json: {
    category_name: mcatName,
    mcat_id: mcatId,
    finalized_specs: {
      finalized_primary_specs: { specs: primary },
      finalized_secondary_specs: { specs: secondary },
      finalized_tertiary_specs: { specs: tertiary }
    }
  }
}];

const data = $json;

const mcat_name = data.mcat_name;
const normalized = data.normalized_candidate_specs || [];

const candidate_specs = normalized.map(spec => ({
  spec_name: spec.spec_name,
  sample_values: spec.sample_values || [],
  sources: spec.sources || []
}));

return [
  {
    json: {
      mcat_name,
      candidate_specs
    }
  }
];

const raw = $json.output;

// Strip markdown code fences if present
const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

const parsed = JSON.parse(cleaned);

return [{ json: parsed }];

const data = $json;

const candidateSpecs = data.normalized_candidates_added.map(spec => ({
  spec_name: spec.spec_name,
  sample_values: spec.sample_values || [],
  sources: spec.sources || []
}));

return [
  {
    json: {
      mcat_id: data.mcat_id,
      mcat_name: data.mcat_name,
      candidate_specs: candidateSpecs
    }
  }
];
